import{_ as e,c as i,o as t,a2 as a}from"./chunks/framework.CS5KOtNG.js";const g=JSON.parse('{"title":"","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"DockerBuild.md","filePath":"DockerBuild.md"}'),s={name:"DockerBuild.md"},l=a(`<h2 id="dockerbuild" tabindex="-1">DockerBuild <a class="header-anchor" href="#dockerbuild" aria-label="Permalink to &quot;DockerBuild&quot;">​</a></h2><blockquote><p>Docker构建</p></blockquote><p>我们在使用 Docker 引擎时，也经常使用 Docker Build ，可能我们平时只使用一些命令（docker build），但是实际上 Docker Build 不单单只是工具的集合，而是能辅助您构建工作流（workflow tasks）和提供更多复杂、高级的场景。</p><ul><li>打包您的软件：构建和打包您的程序，在本地或者云上运行；</li><li>多阶段构建：使您的镜像足够小和安全；</li><li>多平台镜像：构建、推送、拉取镜像，在不同的（操作）系统架构上流畅运行；</li><li>云构建：利用云平台进行镜像构建； （等等以上）</li></ul><h3 id="架构" tabindex="-1">架构 <a class="header-anchor" href="#架构" aria-label="Permalink to &quot;架构&quot;">​</a></h3><p><img src="https://cdn.jsdelivr.net/gh/Github-Stephen/blogPic/springboot/20240320083210.png" alt="20240320083210"></p><p>我们可以查看上面的架构图，Docker Build 是 Client-Server 架构，其中 Buildx 是客户端工具，包含命令集合，BuildKit 在服务端进行命令响应。</p><h3 id="打包镜像" tabindex="-1">打包镜像 <a class="header-anchor" href="#打包镜像" aria-label="Permalink to &quot;打包镜像&quot;">​</a></h3><br><h4 id="dockerfile" tabindex="-1">DockerFile <a class="header-anchor" href="#dockerfile" aria-label="Permalink to &quot;DockerFile&quot;">​</a></h4><p>我们可以把DockerFile理解为制作镜像的模版，模板描述成怎样，镜像就制作成怎样。DockerFile是一个文本文件，里面包含制作镜像的内容，所以掌握基础的DockerFile的写法至关重要。</p><p>以下是最常用的语法结构：</p><table tabindex="0"><thead><tr><th>语法</th><th>描述</th></tr></thead><tbody><tr><td><code>FROM &lt;image&gt;</code></td><td>定义一个镜像的基础，通常是小型操作系统，如 debian</td></tr><tr><td><code>RUN &lt;command&gt;</code></td><td>在当前镜像层之上执行任何命令</td></tr><tr><td><code>WORKDIR &lt;directory&gt;</code></td><td>工作目录，可以紧跟着<code>RUN</code>,<code>CMD</code>,<code>ENTRYPOINT</code>,<code>COPY</code>,<code>ADD</code> ，也就是这些命令将要操作的目录</td></tr><tr><td><code>COPY &lt;src&gt; &lt;dest&gt;</code></td><td>复制文件或者目录 src 到运行容器 dest 路径中</td></tr><tr><td><code>CMD &lt;command&gt;</code></td><td>定义一个脚本，可以在容器启动时执行一次。每个DockerFile只能有一个 CMD 命令，如果存在多个，则最后一个生效</td></tr></tbody></table><h5 id="filename" tabindex="-1">filename <a class="header-anchor" href="#filename" aria-label="Permalink to &quot;filename&quot;">​</a></h5><p>一般来说，我们使用默认名称 DockerFile（没有扩展名） 来新建 DockerFile 文件，如果需要自定义名字，建议使用 <code>somethine.DockerFile</code> 来命名，同时在构建<code>docker build</code>时加入参数<code>--file</code> 指定 DockerFile 的名称。</p><h4 id="docker-镜像" tabindex="-1">Docker 镜像 <a class="header-anchor" href="#docker-镜像" aria-label="Permalink to &quot;Docker 镜像&quot;">​</a></h4><h5 id="网络延迟" tabindex="-1">网络延迟 <a class="header-anchor" href="#网络延迟" aria-label="Permalink to &quot;网络延迟&quot;">​</a></h5><p>由于国内访问官方的docker镜像地址存在很大延迟情况，所以我们需要通过一些加速的办法来提升拉取镜像的速度</p><ul><li>加入镜像地址</li></ul><p>修改docker配置文件</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vi</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/docker/deamon.json</span></span></code></pre></div><p>加入以下配置：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;registry-mirrors&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://xxxxxx.mirror.aliyuncs.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://hub-mirror.c.163.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://registry.aliyuncs.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://docker.mirrors.ustc.edu.cn&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>以上加入了个人的镜像地址，阿里云、网易等镜像加速地址。</p><ul><li>修改配置需要重启docker服务：</li></ul><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">service</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span></span></code></pre></div>`,26),o=[l];function d(r,c,n,h,p,k){return t(),i("div",null,o)}const b=e(s,[["render",d]]);export{g as __pageData,b as default};
